/* ============================================================
   MODULE 4 QUESTION BANK — Debit, Credit, Prepaid, Commercial Cards
   100 Questions
   ============================================================ */
window.QB_M4 = [

  /* ── FOUR-PARTY MODEL (1-10) ── */
  {q:"In the four-party card model, which entity SETS the interchange rate schedule?", options:["The issuing bank","The acquiring bank","The card network (Visa or Mastercard)","The CFPB"], answer:2, explanation:"Visa and Mastercard set and publish the interchange rate schedules — categorized by card type, transaction type, merchant category, and data quality. These published rates are the basis for what the acquirer pays the issuer on every transaction."},
  {q:"Which entity in the four-party model bears the credit risk on credit card transactions?", options:["The card network (Visa/Mastercard)","The acquiring bank","The issuing bank","The merchant"], answer:2, explanation:"The issuing bank bears the credit risk — it extends credit to the cardholder and is responsible for collecting repayment. If the cardholder defaults, the issuer absorbs the loss. This credit risk is why issuers earn interchange to compensate for their underwriting and risk exposure."},
  {q:"Which party in a card transaction receives the Merchant Discount Rate (MDR) payment?", options:["The card network directly","The issuing bank","The acquiring bank (which distributes interchange to the issuer and assessment to the network)","The merchant"], answer:2, explanation:"The merchant pays the MDR to the acquiring bank. The acquirer then distributes funds: interchange goes to the issuing bank (via the network), assessment fees go to the card network, and the acquirer retains its markup. The merchant receives net proceeds."},
  {q:"Visa and Mastercard are best described as:", options:["Banks that issue credit cards and lend money to consumers","Payment networks that route messages and set rules — they do NOT issue cards or lend money","Government-owned payment infrastructure","Credit card manufacturers that produce physical cards"], answer:1, explanation:"Visa and Mastercard are network operators — they provide the switching infrastructure, set operating rules and interchange schedules, manage fraud standards, and earn assessment fees. They do not issue cards, extend credit, or hold consumer deposits. Issuing banks do those things."},
  {q:"American Express historically differs from Visa/Mastercard because:", options:["Amex charges lower fees than Visa/Mastercard","Amex has traditionally operated a closed-loop three-party model — acting as both issuer and acquirer","Amex is a non-profit cooperative","Amex does not use interchange — it charges annual fees only"], answer:1, explanation:"Amex has historically operated a closed-loop model where it issues cards directly to consumers AND contracts directly with merchants — acting as both issuer and acquirer. This gives Amex full control of the relationship and enables premium data analytics, but historically limited acceptance due to higher MDR."},
  {q:"In the four-party model, what is the role of the acquiring bank (merchant bank)?", options:["To issue cards to consumers","To process transactions for merchants: provide POS infrastructure, route auth requests, and deposit net funds to merchant accounts","To set interchange rates on behalf of merchants","To manage cardholder rewards programs"], answer:1, explanation:"The acquiring bank (also called merchant bank or merchant acquirer) is the financial institution that contracts with merchants to accept card payments. It provides or arranges POS equipment/gateway, routes authorization requests through the network, and settles funds (net of MDR) to the merchant's account."},
  {q:"A consumer's Chase Sapphire Reserve Visa card is used at Marriott. Which party is the 'issuer' in this transaction?", options:["Visa","Marriott","Chase (JPMorgan Chase)","Marriott's acquiring bank"], answer:2, explanation:"The issuer is JPMorgan Chase — the bank that issued the Chase Sapphire Reserve card to the consumer. Visa is the network. Marriott's bank (acquirer) processes the merchant side. JPMorgan Chase approved or declined the auth, bears the credit risk, and earns interchange."},
  {q:"The 'Merchant Discount Rate' (MDR) is best defined as:", options:["A discount merchants receive for accepting cash instead of cards","The total fee the merchant pays to their acquirer as a percentage of each card transaction","The fee card networks charge directly to consumers","A government-mandated cap on merchant card fees"], answer:1, explanation:"The MDR is the all-in fee a merchant pays their acquirer on each card transaction. It includes: interchange (paid to the issuer), network assessment (paid to Visa/MC), and the acquirer's markup. MDR varies by card type, merchant category, and transaction method — typically 1.5% to 3.5%+ for most merchants."},
  {q:"Discover was acquired by which company in 2024?", options:["American Express","JPMorgan Chase","Capital One","Bank of America"], answer:2, explanation:"Capital One announced the acquisition of Discover Financial Services in 2024 — one of the most significant payments industry consolidations in years. This would give Capital One access to Discover's closed-loop network, enabling Capital One to become both issuer and network operator."},
  {q:"Which entity in a card transaction guarantees the merchant will be paid?", options:["The issuing bank","The card network","The acquiring bank","The cardholder"], answer:2, explanation:"The acquiring bank guarantees payment to the merchant — it assumes the risk that the transaction will settle correctly. Even if the card issuer has issues, the acquirer is contractually obligated to pay the merchant (though chargebacks can later claw back funds). This guarantee is why merchants trust card acceptance."},

  /* ── AUTHORIZATION FLOW (11-20) ── */
  {q:"What is the first step in the card authorization flow?", options:["The issuer approves or declines the transaction","The merchant submits a batch close","The card is presented at the terminal — chip/tap/swipe reads card data","The acquirer sends a settlement file"], answer:2, explanation:"The authorization flow begins when the card is presented at the terminal. The terminal reads card data (PAN, expiry, CVV/cryptogram) via EMV chip, NFC contactless tap, or magnetic stripe swipe, then initiates the authorization request."},
  {q:"What does the BIN (Bank Identification Number) do during authorization?", options:["It contains the cardholder's PIN for verification","It identifies the card network and issuing bank, enabling the acquirer to route the auth request correctly","It stores the transaction amount and merchant ID","It is the checksum digit validating the full PAN"], answer:1, explanation:"The BIN (first 6-8 digits of the PAN) identifies the card network (Visa, MC, Amex, etc.) and the specific issuing bank. The acquirer uses the BIN to route the authorization request to the correct card network, which then routes to the appropriate issuing bank."},
  {q:"Which authorization response code means 'Approved'?", options:["00","05","51","57"], answer:0, explanation:"Response code '00' means Approved. Other common codes: '05' = Do Not Honor (generic decline), '51' = Insufficient Funds, '54' = Expired Card, '57' = Transaction Not Permitted to Cardholder."},
  {q:"An authorization hold at a hotel differs from the final charge because:", options:["Authorization holds are permanent while the final charge is temporary","The hotel places a hold for estimated expenses plus incidentals; the final charge reflects actual consumption — they may differ significantly","Authorization holds are charged to the credit card while the final charge goes to a debit card","Hotels are exempt from the authorization system and charge cards directly"], answer:1, explanation:"Hotels pre-authorize an amount covering the room rate plus estimated incidentals (minibar, room service, parking). The actual final charge reflects what was consumed. The hold reduces available credit/balance; the final settled amount may be higher or lower. Holds expire if not settled within 7-30 days."},
  {q:"What is 'Stand-In Processing (STIP)' in card authorization?", options:["A backup process where the merchant manually approves transactions","The card network approves or declines transactions on the issuer's behalf when the issuer's systems are down","A regulatory fallback for when the consumer's PIN is forgotten","The process of settling transactions when the merchant's terminal is offline"], answer:1, explanation:"STIP occurs when the card issuer's authorization system is unavailable. Visa or Mastercard steps in, using stored issuer parameters (velocity limits, floor limits) to approve or decline transactions. This protects merchants from lost sales during issuer outages, but creates risk if the network's parameters are outdated."},
  {q:"What is the typical end-to-end time for a card authorization to complete?", options:["30-60 seconds","10-15 seconds","Under 2 seconds","5-10 minutes"], answer:2, explanation:"Card authorization is extremely fast — typically completing in under 2 seconds end-to-end. The message travels from the merchant terminal to the acquirer, through the card network, to the issuer, and back — often spanning thousands of miles — in milliseconds."},
  {q:"A $1 pre-authorization at a gas station is designed to:", options:["Charge the consumer $1 for starting the pump","Verify the card is valid and has some available balance before allowing fuel to be pumped","Set the maximum amount the consumer can spend on fuel","Automatically charge $1 per gallon pumped"], answer:1, explanation:"Gas stations pre-auth $1 (or sometimes $100+ for potential large fill-ups) to verify the card is valid and has a balance before enabling the pump. After fueling, the authorization is updated (or a new one placed) for the actual amount, and the $1 pre-auth eventually falls off."},
  {q:"During card authorization, the issuer's fraud scoring system evaluates which of the following?", options:["Only the transaction amount and merchant category","Only the cardholder's FICO credit score","Multiple signals including location, spending velocity, device fingerprint, purchase category, and behavioral patterns","Only whether the card has been reported lost or stolen"], answer:2, explanation:"Modern issuer fraud scoring uses hundreds of signals in real time: geographic location (is this purchase consistent with prior behavior?), spending velocity (too many transactions too fast?), merchant category (unusual for this cardholder?), device data (for CNP), and ML-based behavioral modeling. A single FICO score is insufficient for real-time fraud decisions."},
  {q:"What is an 'authorization hold' and when does it fall off?", options:["A permanent transaction charge; it never falls off","A temporary reduction in available balance that the issuer maintains until either the transaction settles or the hold expires (typically 3-7 days for retail, up to 30 days for some travel)","A 24-hour security freeze applied to all new accounts","An automatic $1 deducted from the account at time of authorization"], answer:1, explanation:"An authorization hold is temporary — it reduces available credit/balance but is NOT a final charge. It falls off either when: (1) the transaction clears/settles, replacing the hold with the actual charge; or (2) the hold expiration period passes without settlement. Most retail holds expire after 3-7 days; travel/hotel/car rental holds can last up to 30 days."},
  {q:"What does the acquirer add to the authorization request before forwarding it to the card network?", options:["The consumer's PIN verification","Merchant data: Merchant Category Code (MCC), merchant ID, terminal ID, and merchant location","The consumer's credit score","A transaction fee pre-authorization"], answer:1, explanation:"The acquirer appends merchant identifying information to the authorization request: the Merchant Category Code (MCC), merchant ID, terminal ID, and merchant location (country, postal code). This data enables the issuer to perform risk analysis and determines interchange category for the eventual settlement."},

  /* ── CLEARING & SETTLEMENT (21-28) ── */
  {q:"How does card clearing differ from authorization?", options:["Clearing happens in real time; authorization happens at end of day","Authorization is real-time and individual; clearing is batch-based, occurring when the merchant submits transactions for settlement","Clearing is done by the consumer; authorization is done by the bank","There is no difference — they happen simultaneously"], answer:1, explanation:"Authorization is real-time — it happens in seconds when the card is presented. Clearing is batch — the merchant submits all authorized transactions (typically at end-of-day batch close) for clearing through the network. Settlement (funds transfer) then follows clearing by T+1 or T+2."},
  {q:"What is 'batch close' in card payments?", options:["When the card network closes for the day","The end-of-day process where a merchant submits all the day's authorized transactions to their acquirer for clearing and settlement","When a consumer closes their credit card account","The Federal Reserve's daily settlement of interchange between banks"], answer:1, explanation:"Batch close (or batch settlement) is when the merchant's POS system sends all the day's authorized transaction records to the acquirer for processing. Without batch close, authorizations stay as holds and never settle. Most systems do automatic batch close at midnight or a set time."},
  {q:"In card settlement, merchants receive funds 'net' of fees. This means:", options:["The merchant pays a separate invoice for card fees at month-end","The MDR is deducted before the acquirer deposits funds to the merchant's bank account","The merchant receives the full transaction amount and is billed separately","Net means the merchant receives nothing — all funds go to the issuer"], answer:1, explanation:"Merchants receive net settlement — the MDR is deducted upfront before funds hit their bank account. For a $100 transaction with 2.5% MDR, the merchant receives $97.50. This contrasts with ACH where the full amount is received and fees are separate."},
  {q:"After a card transaction is authorized, can the merchant increase the settlement amount above the authorized amount?", options:["Yes, for any reason without limit","Only in specific situations (restaurants for tips, hotels for incidentals) where card networks have specific rules allowing adjustments within a tolerance","No — the settlement amount must exactly match the authorized amount","Yes, but only if the increase is under $10"], answer:1, explanation:"Card network rules allow incremental adjustments in specific contexts. Restaurants can add tips above the authorized amount (within network-defined tolerances). Hotels can add incidental charges. In most other retail contexts, the settlement amount should match (or be less than) the authorized amount."},
  {q:"What is the typical settlement timeline for Visa/Mastercard credit card transactions to a merchant?", options:["Same day (immediate)","Next day (T+1)","Two days (T+2)","Five days (T+5)"], answer:1, explanation:"Most merchants receive card settlement funds from their acquirer within T+1 — one business day after batch close. Some acquirers may offer same-day or next-morning funding for an additional fee. The card network's internal settlement between issuer and acquirer also generally occurs at T+1."},
  {q:"Who ultimately bears the cost of interchange in the card payments system?", options:["The cardholder through annual fees","The card network through its assessment fees","The merchant — it is embedded in the Merchant Discount Rate they pay","The issuing bank — it funds interchange from its own capital"], answer:2, explanation:"The merchant ultimately bears interchange cost — it's included in the MDR the merchant pays to the acquirer. The acquirer forwards interchange to the issuer. This is why merchants in many countries have lobbied for interchange caps (like the EU's 0.3% cap) — it directly affects their cost of acceptance."},
  {q:"Does an authorization guarantee that a card transaction will not be charged back?", options:["Yes — an approved authorization means the transaction is final","No — authorization only verifies funds availability and basic fraud checks at the time; chargebacks can still occur after settlement","Yes, but only for EMV chip transactions","No, but chargeback risk is eliminated when a PIN is used"], answer:1, explanation:"Authorization does NOT guarantee against chargebacks. Authorization checks: is the account valid, is there available balance/credit, does the fraud score pass? It does not verify whether the cardholder authorized this specific purchase (for CNP fraud), whether they'll dispute receiving goods, or whether merchant fulfillment is satisfactory."},
  {q:"What is 'interchange' in the context of card payments?", options:["The process of exchanging authorization messages between banks","The fee the acquiring bank pays to the issuing bank on each card transaction, set by the card network","The fee cardholders pay for international transactions","The wire transfer used to settle card transactions between banks"], answer:1, explanation:"Interchange is the per-transaction fee paid by the merchant's acquirer to the cardholder's issuer. Set by Visa/Mastercard and published in interchange tables, it is the largest component of the MDR. It compensates the issuer for credit risk, fraud losses, and the cost of issuing/maintaining the card."},

  /* ── INTERCHANGE ECONOMICS (29-40) ── */
  {q:"The Durbin Amendment caps debit interchange for which category of bank issuers?", options:["All US banks regardless of size","Banks with assets over $10 billion","Banks with assets over $50 billion","Only the 10 largest US banks by deposits"], answer:1, explanation:"The Durbin Amendment (Dodd-Frank Section 1075, Regulation II) caps debit card interchange for issuers with $10 billion or more in total assets. Smaller issuers (under $10B) are nominally exempt and can earn market-rate interchange."},
  {q:"What is the Durbin Amendment's debit interchange cap for covered issuers (approximately)?", options:["$0.05 + 0.01% per transaction","$0.21 + 0.05% per transaction (+ $0.01 fraud adjustment)","$0.50 flat per transaction","1.5% of transaction amount"], answer:1, explanation:"The Durbin cap for covered issuers (assets ≥$10B) is $0.21 + 0.05% of the transaction amount + $0.01 fraud prevention adjustment. This replaced pre-Durbin average rates of around $0.44 per transaction — roughly halving debit interchange revenue for large issuers."},
  {q:"What is the 'dual-network routing' requirement introduced by Durbin?", options:["Merchants must accept both Visa and Mastercard","Every debit card must carry two unaffiliated network brands, and merchants can choose which network to route through","Banks must offer both signature and PIN debit on every card","Acquirers must route to the lowest-cost network automatically"], answer:1, explanation:"Durbin's routing provision requires every debit card to carry at least two unaffiliated payment networks (e.g., Visa + Star, or Mastercard + NYCE). Merchants choose which network processes the transaction — usually preferring the cheaper PIN network over Visa/MC signature debit."},
  {q:"How did Durbin most directly impact large bank retail consumers?", options:["Banks were required to reduce credit card APRs","Large banks eliminated most free checking accounts and debit rewards programs to offset lost interchange revenue","Banks reduced mortgage rates to retain customers","Consumers received rebates from the interchange savings"], answer:1, explanation:"Durbin cost large bank issuers ~$8-10 billion in annual interchange revenue. Their response: eliminating free checking accounts (requiring minimum balances or monthly fees), eliminating debit card rewards programs (no longer profitable at capped rates), and adding various service fees."},
  {q:"How do neobanks like Chime fund their 'no fee' business model using debit interchange?", options:["Chime operates at a loss indefinitely, funded by VC capital","Chime partners with banks under $10B (Durbin-exempt) like Bancorp Bank, earning full market-rate interchange on its debit cards","Chime earns revenues only from interest on customer savings balances","Chime charges merchants a separate fee directly"], answer:1, explanation:"Chime and similar neobanks partner with small banks (e.g., Bancorp Bank, Stride Bank) that are under the $10B Durbin threshold. These banks are exempt from the cap, earning full market-rate debit interchange (~$0.50-$0.80 per transaction). Chime shares in this interchange — funding its fee-free model."},
  {q:"Interchange rates for credit cards are generally HIGHER than for debit cards because:", options:["Credit cards are more expensive to produce physically","Credit cards carry credit risk (possibility of default) that the issuer must be compensated for, plus fund expensive rewards programs","Credit cards have more fraud than debit cards in aggregate","Card networks charge higher assessment fees on credit transactions"], answer:1, explanation:"Credit card interchange is higher because: (1) issuers extend credit — they risk non-payment and must be compensated for that risk; (2) credit card rewards programs (cash back, miles, points) are primarily funded by interchange — premium rewards cards have correspondingly high interchange; (3) average credit card transaction amounts are higher."},
  {q:"A 'Level 3 data' transaction in commercial card payments refers to:", options:["A transaction with three-factor authentication","A commercial card transaction that includes full line-item detail (item description, quantity, unit price, product codes) in the authorization/settlement data","A transaction requiring three network approvals","A transaction settled three days after authorization"], answer:1, explanation:"Level 3 data is the highest richness of purchase data that can accompany a commercial card transaction — including itemized line-item detail, tax amounts, freight, and product codes. Level 3 data submission earns lower interchange rates for B2B transactions, as it provides enhanced visibility that reduces the network's risk premium."},
  {q:"Network assessment fees (charged by Visa/Mastercard) are approximately:", options:["1.5-2% of transaction value","0.5-0.75% of transaction value","0.13-0.15% of transaction value","$0.50 flat per transaction"], answer:2, explanation:"Visa and Mastercard charge network assessment fees of approximately 0.13-0.15% (13-15 basis points) of each transaction amount. These fees — much smaller than interchange — are the networks' primary revenue source. On $10 trillion+ in annual transaction volume, even these small percentages generate billions in revenue."},
  {q:"What happened to debit card rewards programs at large US banks after the Durbin Amendment?", options:["They became more generous to offset customer frustration","They were largely eliminated — the capped interchange rate no longer provides sufficient revenue to fund rewards","They were transferred to credit cards only","They were replaced by government-mandated cash-back programs"], answer:1, explanation:"Major banks (Chase, BofA, Wells Fargo) eliminated their debit card rewards programs after Durbin. Pre-Durbin, higher debit interchange funded these programs. At $0.21 + 0.05% per transaction (vs. ~$0.44 previously), there is insufficient interchange to fund meaningful rewards and still operate profitably."},
  {q:"Card-present (CP) transactions generally have LOWER interchange than card-not-present (CNP) transactions because:", options:["CP terminals are more expensive to operate","CP transactions have lower fraud risk (the physical card and cardholder are present, often with chip/tap authentication), reducing the issuer's fraud exposure","CP merchants have more loyal customers","CNP merchants pay lower MDR, so interchange must compensate"], answer:1, explanation:"CP interchange is lower because fraud risk is substantially lower when the physical card is present — especially with EMV chip or contactless NFC, which use per-transaction cryptograms that make counterfeiting practically impossible. CNP (e-commerce) transactions have higher fraud rates (no physical card verification), warranting higher interchange to compensate the issuer."},
  {q:"'Durbin 2.0' refers to:", options:["A 2022 increase to the Durbin interchange cap","A 2023 Federal Reserve proposed rule extending debit routing requirements to card-not-present (online) transactions","A 2024 CFPB rule capping all interchange at 0.5%","A Visa/Mastercard voluntary program to reduce debit interchange"], answer:1, explanation:"'Durbin 2.0' refers to the Federal Reserve's 2023 proposed rulemaking that would extend the dual-network routing requirements to card-not-present (e-commerce/online) debit transactions — an area currently dominated by Visa/Mastercard since PIN debit networks aren't typically available online."},
  {q:"Which category of card product typically earns the HIGHEST interchange rate?", options:["Standard consumer debit (large bank)","Standard consumer credit","Premium consumer rewards credit (e.g., signature, infinite)","Prepaid government benefit cards"], answer:2, explanation:"Premium consumer rewards credit cards (e.g., Visa Signature, Infinite; Mastercard World Elite) carry the highest interchange rates — often 2.3-3.5%+ — because they are used by high-spend consumers and because the issuer needs to fund generous rewards programs. Government benefit prepaid and large-bank debit have the lowest interchange."},

  /* ── BIN / IIN STRUCTURE (41-48) ── */
  {q:"What do the first digits of a Visa card number always start with?", options:["3","4","5","6"], answer:1, explanation:"Visa card numbers always begin with the digit 4. Mastercard begins with 51-55 or 2221-2720. American Express begins with 34 or 37. Discover begins with 6011, 644-649, or 65."},
  {q:"What is the standard length of a card PAN (Primary Account Number)?", options:["12 digits","14 digits","15 digits (Amex) or 16 digits (Visa/MC)","Always 16 digits"], answer:2, explanation:"Most cards (Visa, Mastercard, Discover) use 16-digit PANs. American Express uses 15-digit PANs. Some specialized cards (Maestro) may use other lengths. The industry is standardizing on 16 digits with the 8-digit BIN migration."},
  {q:"The Luhn algorithm (Mod 10) validates which part of a card number?", options:["The BIN prefix identifies the correct network","The full PAN has a valid check digit (last digit)","The middle 6 digits represent the account number","The expiry date is mathematically consistent with the PAN"], answer:1, explanation:"The Luhn algorithm validates the full PAN by checking that the check digit (the last digit) is consistent with the other digits. Any system can validate a card number's format without contacting a bank. However, it only checks mathematical validity — not whether the account actually exists or has funds."},
  {q:"What information can typically be derived from a card's BIN?", options:["The cardholder's name and credit limit","The card network, issuing bank, card type (debit/credit/prepaid), country of issuance, and reward tier","The card's CVV and PIN","The cardholder's outstanding balance"], answer:1, explanation:"A BIN lookup reveals: which network the card is on, which specific bank issued it, whether it's a debit/credit/prepaid card, the country of issuance, whether it's a commercial card, and often the reward tier (standard, gold, signature, etc.). This data is critical for interchange rate determination and fraud analysis."},
  {q:"Why is the industry migrating from 6-digit to 8-digit BINs?", options:["8-digit BINs are more secure than 6-digit BINs","The 6-digit BIN space has run short of available numbers as card products proliferated; 8-digit BINs provide vastly more routing capacity","8-digit BINs are required by EU regulations","Visa and Mastercard want to charge more for BIN registration"], answer:1, explanation:"The 6-digit BIN space has become exhausted as the number of card programs (issuers, product types, countries) expanded globally. ISO mandated migration to 8-digit BINs (IINs), maintaining the 16-digit PAN structure but shifting 2 digits from the account number portion to the BIN, enabling millions more unique BINs."},
  {q:"In a card transaction, which entity uses the BIN to route the authorization request?", options:["The consumer's mobile banking app","The merchant's terminal","The acquirer / payment processor","The card network"], answer:2, explanation:"The acquirer (or payment processor) reads the BIN from the card data and uses it to determine which card network to send the authorization request to. Once at the network level, the BIN table is used again to route to the specific issuing bank's authorization system."},
  {q:"What is 'network tokenization' and how does it relate to the PAN?", options:["Network tokenization replaces the PAN with a randomly generated token specific to each merchant/digital wallet. The actual PAN is never shared with the merchant.","Network tokenization is when banks convert physical card numbers to digital format","Network tokenization is a SWIFT process for international payment routing","Tokenization is another word for encryption of the full PAN"], answer:0, explanation:"Network tokenization (used in Apple Pay, Google Pay, Samsung Pay) replaces the actual card PAN with a network-issued token. Each merchant/wallet gets a unique token for the same card. If a merchant is breached and the token is stolen, it's useless elsewhere — dramatically reducing CNP fraud risk."},
  {q:"What does MCC (Merchant Category Code) determine in card processing?", options:["The merchant's credit score","The interchange rate category and transaction restrictions (e.g., fleet card MCC restrictions)","The maximum transaction size allowed","The card network assigned to process the transaction"], answer:1, explanation:"The MCC categorizes merchants by business type (e.g., 5411 = Grocery Stores, 5812 = Restaurants, 4111 = Transportation). MCCs determine: interchange rate category (groceries get different rates than airlines), fleet card restrictions (only certain MCCs can charge fleet cards), and issuer velocity/fraud rules."},

  /* ── DEBIT CARDS & REG E (49-58) ── */
  {q:"Debit cards draw funds from which account type?", options:["A revolving line of credit","A demand deposit account (checking/DDA)","A money market investment account","A prepaid stored-value account"], answer:1, explanation:"Debit cards are linked directly to a demand deposit account (DDA) — typically a checking account. Spending is limited to available funds in the account (subject to overdraft policies). Unlike credit cards, no credit is extended; it's the cardholder's own deposited money."},
  {q:"Under Regulation E, what is the maximum consumer liability for unauthorized debit card transactions reported within 2 business days?", options:["$0","$50","$500","Unlimited"], answer:1, explanation:"If an unauthorized electronic fund transfer (including a debit card transaction) is reported within 2 business days of the consumer learning of the loss, the consumer's maximum liability under Reg E is $50. The bank covers all amounts above $50."},
  {q:"Under Regulation E, what happens to consumer liability if the unauthorized transaction is NOT reported within 60 days of the bank statement?", options:["Liability remains capped at $500","Liability increases to $1,000","Liability can become unlimited — the bank is not required to cover losses beyond the 60-day period","Liability drops to $0 if the consumer files a police report"], answer:2, explanation:"If an unauthorized transaction appears on a statement and the consumer fails to report it within 60 calendar days of statement delivery, consumer liability can be unlimited for subsequent transactions that occur after the 60-day period. This strict timeline incentivizes consumers to review statements promptly."},
  {q:"Regulation E's overdraft opt-in rule requires consumers to:", options:["Opt out of overdraft protection every year","Affirmatively opt IN to overdraft coverage for one-time debit card transactions and ATM withdrawals — without opt-in, these transactions are declined rather than creating an overdraft","Accept automatic overdraft enrollment when opening an account","Pay a $10 fee to access overdraft protection"], answer:1, explanation:"The 2010 Reg E amendment requires banks to obtain explicit consumer opt-in before charging overdraft fees on one-time debit card transactions and ATM withdrawals. Without opt-in, the bank must decline the transaction at the point of sale rather than allow an overdraft. The opt-in rule significantly reduced bank overdraft fee revenue from these transaction types."},
  {q:"Does Regulation E protect business account holders against unauthorized debit card transactions?", options:["Yes — Reg E protects all account holders regardless of account type","No — Reg E only applies to consumer accounts; business accounts are governed by UCC Article 4 and bank-specific agreements","Yes, but with a lower protection cap of $100","Only if the business has fewer than 10 employees"], answer:1, explanation:"Reg E explicitly applies to consumer accounts. Business accounts are governed by commercial bank agreements and UCC Article 4, which typically have shorter reporting windows (24-48 hours for some banks) and less protective terms. This makes fraud control systems critical for business banking customers."},
  {q:"A bank has 10 business days to investigate a Reg E dispute. What must the bank do if it needs more time?", options:["It can take as long as needed with no obligation to the consumer","It must provide provisional credit to the consumer's account and can extend the investigation to 45 calendar days (90 days for new accounts or point-of-sale transactions)","It must immediately rule in the consumer's favor","It must file a SAR with FinCEN before extending the timeline"], answer:1, explanation:"If a bank needs more than 10 business days to investigate a Reg E error, it must provisionally credit the disputed amount to the consumer's account within 10 business days and can then take up to 45 calendar days total (or 90 calendar days for new accounts, foreign, or POS transactions) to complete its investigation. 'Business days' applies only to the initial 10-day investigation window — the extension is measured in calendar days."},
  {q:"What distinguishes 'signature debit' from 'PIN debit' transactions?", options:["Signature debit requires a written signature on paper; PIN debit is fully digital","Signature debit routes through Visa/MC networks using cardholder signature (or no verification); PIN debit routes through EFT networks (Star, NYCE) using a 4-digit PIN","Signature debit settles instantly; PIN debit settles in 3 days","Signature debit has lower interchange; PIN debit has higher interchange"], answer:1, explanation:"Signature debit routes through the major card networks (Visa/MC) and is processed like a credit transaction — higher interchange, slightly slower settlement. PIN debit routes through regional EFT networks (Star, NYCE, Pulse, Interlink) using PIN verification — lower interchange, often faster settlement, cash-back-at-POS capable."},
  {q:"The 2015 EMV liability shift changed card fraud responsibility in what way?", options:["Issuers became responsible for all fraud regardless of terminal type","Merchants without chip-capable terminals now bear counterfeit card fraud liability for transactions that could have been detected by chip technology","Consumers became liable for all fraud if they don't report within 24 hours","The Federal Reserve now covers all card fraud losses"], answer:1, explanation:"The US EMV liability shift (October 2015) transferred counterfeit fraud liability: previously issuers bore this cost; now if a merchant uses a non-chip-capable terminal and a counterfeit EMV chip card is used, the merchant (not the issuer) bears the fraud loss. This drove rapid adoption of chip terminals."},
  {q:"Visa Direct and Mastercard Send are used to:", options:["Authorize debit card purchases in real time","Push funds to a recipient's debit card within minutes (used for instant payouts, earned wage access, P2P)","Dispute and reverse debit card transactions","Send wire transfers between corporate bank accounts"], answer:1, explanation:"Visa Direct and Mastercard Send are 'push-to-card' programs enabling originators to push funds (credits) to a recipient's debit card number in near real-time. Use cases include: Venmo/PayPal Instant Transfer, Uber Instant Pay, insurance claim payouts, earned wage access. The card number is sufficient — no routing/account number needed."},
  {q:"Which type of debit transaction allows consumers to get cash back at the point of sale?", options:["Signature debit via Visa network","PIN debit via regional EFT networks (Star, NYCE)","Contactless tap-to-pay transactions","All debit transactions support cash back"], answer:1, explanation:"Cash back at the point of sale is a PIN debit feature. When a consumer enters their PIN at a grocery store or other participating merchant, they can request cash back (e.g., $20 or $40) in addition to their purchase. The total debit transaction covers both the purchase and cash back amount. Signature debit terminals generally don't support cash back."},

  /* ── CREDIT CARDS (59-70) ── */
  {q:"Credit cards are best described as:", options:["Debit instruments linked to checking accounts","Revolving lines of credit — the issuer extends credit at the time of purchase; the cardholder repays later","Prepaid instruments funded before spending","A fixed-term loan disbursed monthly"], answer:1, explanation:"Credit cards are revolving credit products — the issuing bank extends credit on each purchase up to the cardholder's credit limit. The cardholder can carry a balance (revolving) and pay interest, or pay in full each month to avoid interest. No pre-funding is required."},
  {q:"The Supreme Court case that enabled credit card issuers to centralize in low-rate states (South Dakota, Delaware) was:", options:["Mastercard v. Visa (1985)","Marquette National Bank v. First of Omaha (1978)","Citizens United v. FEC (2010)","CFPB v. Community Financial Services (2024)"], answer:1, explanation:"Marquette National Bank v. First of Omaha (1978) held that national banks can charge interest rates allowed by the state where they are chartered — regardless of the borrower's state. This enabled issuers to charter in South Dakota and Delaware (which eliminated interest rate caps), enabling modern revolving credit products."},
  {q:"Under the CARD Act (2009), how much advance notice must issuers give before raising a cardholder's interest rate?", options:["7 days","15 days","30 days","45 days"], answer:3, explanation:"The CARD Act requires card issuers to provide 45 days' advance notice before making significant changes to a cardholder's account, including rate increases. During this notice period, the cardholder can opt out (close the account under the old terms)."},
  {q:"The CARD Act prohibits issuers from retroactively applying rate increases to:", options:["All balances on the account","Existing balances — rate increases can only apply to NEW purchases made after the increase takes effect","Balances over $1,000","New cardholders in their first year"], answer:1, explanation:"This is one of the most important CARD Act provisions: rate increases cannot apply retroactively to existing balances. If an issuer raises the APR from 15% to 22%, the existing balance continues at 15%; only new purchases after the effective date accrue interest at 22%."},
  {q:"Under the CARD Act, when a consumer pays more than the minimum on a multi-rate credit card, excess payments are applied to:", options:["The lowest interest rate balance first","Equally across all balances","The highest interest rate balance first","The issuer's discretion"], answer:2, explanation:"Pre-CARD Act, issuers applied excess payments to the lowest-rate balance first — maximizing interest charges on the high-rate balance. The CARD Act reversed this: payments above the minimum must be applied to the HIGHEST interest rate balance first, reducing consumer interest costs."},
  {q:"What is the credit card industry's average APR as of 2024?", options:["~10-12%","~15-17%","~22%+","~30%+"], answer:2, explanation:"As of 2024, the average US credit card APR is approximately 22%+ — the highest in four decades. The combination of Federal Reserve rate hikes (2022-2023) and historically high base rates pushed credit card APRs to levels not seen since the early 1980s."},
  {q:"Credit card 'charge-off rate' refers to:", options:["The percentage of transactions declined by the issuer","The percentage of outstanding balances written off as uncollectible bad debt","The rate at which consumers pay off their balance each month","The percentage of cards closed annually"], answer:1, explanation:"Charge-off rate is the percentage of outstanding credit card balances that issuers write off as uncollectible bad debt — loans the bank no longer expects to recover. As of 2024, the industry average charge-off rate is rising toward 3-4%, with subprime portfolios experiencing 8-10%+."},
  {q:"Which of the following is the LARGEST revenue source for most credit card issuers?", options:["Annual fees","Interchange revenue","Interest income (finance charges on revolving balances)","Late payment fees"], answer:2, explanation:"Interest income — the finance charges on revolving balances — is the single largest revenue source for most credit card issuers. Approximately 55% of US cardholders carry a revolving balance and pay interest, which at 22%+ APR generates enormous interest income relative to the outstanding balance."},
  {q:"A credit card 'co-brand' program is:", options:["A card bearing both Visa and Mastercard logos for dual acceptance","A credit card partnership between a bank issuer and a non-bank brand (airline, hotel, retailer) where both parties share economics and branding","A card with two users (primary and authorized user) on one account","A program where two competing banks jointly issue a credit card"], answer:1, explanation:"Co-brand cards are partnerships between a bank issuer and a non-bank brand. Examples: Chase Sapphire Reserve (Chase + Visa), Delta SkyMiles Gold (Amex + Delta), Marriott Bonvoy Boundless (Chase + Marriott). The brand drives card adoption through its loyalty program; the bank provides credit infrastructure and earns interchange. Both share economics."},
  {q:"What is 'breakage' in the context of rewards programs?", options:["Points that expire before being redeemed, representing revenue to the issuer","Physical credit cards that break or are damaged","Transactions that fail during authorization","Chargebacks that break through Seller Protection"], answer:0, explanation:"Breakage refers to loyalty points, miles, or cash back that is never redeemed — either because they expire, the account closes, or the consumer forgets about them. Breakage is pure profit for the issuer/loyalty program and is a critical financial assumption in rewards program economics."},
  {q:"What does 'revolvers' vs. 'transactors' mean in credit card industry parlance?", options:["Revolvers are fraudsters who open and close accounts; transactors are legitimate users","Revolvers carry a monthly balance and pay interest; transactors pay in full each month and generate no interest income","Revolvers use the card internationally; transactors use it domestically","Revolvers have multiple cards; transactors have only one card"], answer:1, explanation:"'Revolvers' carry a month-to-month balance and pay interest — they are the most profitable customers for issuers. 'Transactors' (sometimes called 'deadbeats' in industry slang) pay in full every month, generating interchange for the issuer but no interest income. Issuers must earn enough interchange from transactors to cover their rewards cost."},
  {q:"3D Secure (3DS) in credit card e-commerce achieves which primary benefit for merchants?", options:["Eliminates all chargebacks automatically","Shifts fraud liability from the merchant to the card issuer for successfully authenticated transactions","Adds encryption to protect cardholder data at rest","Reduces interchange rates for online merchants"], answer:1, explanation:"3DS achieves a liability shift: when the card issuer authenticates the cardholder during checkout (via OTP, biometric, or risk-based assessment), fraud liability transfers from the merchant to the issuer. This protects merchants from 'unauthorized transaction' chargebacks on 3DS-authenticated purchases — dramatically reducing CNP fraud liability exposure."},

  /* ── CHARGEBACKS (71-78) ── */
  {q:"What is a 'chargeback' in the card payments system?", options:["A fee merchants pay for accepting premium reward cards","The reversal of a card transaction by the issuing bank at the consumer's request, debiting the merchant's account","An authorization that expires without settlement","A penalty fee charged to issuers by Visa/Mastercard for excessive declines"], answer:1, explanation:"A chargeback is a transaction reversal initiated by the cardholder through their issuing bank. The issuer reverses the charge, debits the acquirer, and the acquirer debits the merchant's account. The merchant can dispute (re-present) with evidence, but chargebacks create financial and operational burden."},
  {q:"What is 'friendly fraud' in chargebacks?", options:["When friends help each other dispute legitimate charges","When a cardholder disputes a charge they knowingly and legitimately authorized — essentially committing fraud against the merchant","A fraud type where two banks collude against a merchant","When a consumer accepts a partial refund without disputing the full amount"], answer:1, explanation:"Friendly fraud (also called 'first-party fraud') is when a consumer intentionally disputes a legitimate charge — perhaps they received the goods but claim they didn't, or they bought something they later regretted and want a refund without returning the item. Estimated 30-50% of all chargebacks are friendly fraud."},
  {q:"What is the chargeback ratio threshold at which Visa may add a merchant to its 'Chargeback Monitoring Program'?", options:["0.1%","0.5%","0.9% (standard) / 1.8% (excessive)","5%"], answer:2, explanation:"Visa's Chargeback Monitoring Program flags merchants at two tiers: 'Standard' (≥100 chargebacks AND ≥0.9% ratio) and 'Excessive' (≥1,000 chargebacks AND ≥1.8% ratio). Consequences include financial fines and ultimately potential termination of card acceptance privileges."},
  {q:"What does it mean to 're-present' a chargeback?", options:["To file a second chargeback on the same transaction","For the merchant to respond to a chargeback by submitting evidence proving the original transaction was valid","To request the card network to arbitrate between issuer and acquirer","To re-authorize a declined transaction"], answer:1, explanation:"Representment is the merchant's formal dispute of a chargeback. The merchant submits compelling evidence to their acquirer — shipping confirmation, signed receipt, IP/device data, communication records — which the acquirer forwards to the issuing bank to argue the chargeback should be reversed."},
  {q:"What is 'Visa reason code 13.1' in a chargeback context?", options:["Fraud — No Cardholder Authorization","Item Not Received — consumer claims ordered goods/services were not received","Late Presentment — merchant submitted the transaction too late","Credit Not Processed — refund was promised but not issued"], answer:1, explanation:"Visa reason code 13.1 is 'Merchandise/Services Not Received' — the buyer claims they paid for goods or services that were never delivered. This is one of the most common chargeback reason codes for e-commerce merchants and requires evidence of delivery (tracking, proof of download for digital goods)."},
  {q:"How long does a typical US consumer have to initiate a credit card chargeback dispute?", options:["30 days from transaction date","60 days from transaction date","120 days from the transaction date (or delivery date for non-received items)","1 year from transaction date"], answer:2, explanation:"For most credit card chargebacks under Visa/Mastercard rules, the consumer has 120 calendar days from the transaction date (or from the expected delivery date for items not received) to dispute with their issuer. The issuer may have additional internal policies. Some reason codes have shorter windows."},
  {q:"The MATCH list (Member Alert to Control High-Risk Merchants) is:", options:["A list of the best-performing merchants in the Visa/MC ecosystem","A database of merchants and their principals who have been terminated for cause (excessive chargebacks, fraud, bankruptcy) — considered blacklisted from card acceptance","A marketing list of high-spend consumers","A list of merchants exempt from chargeback limits"], answer:1, explanation:"MATCH (formerly TMF — Terminated Merchant File) is a database maintained by Mastercard listing merchants and their owners/principals who have been terminated for cause. Acquirers must check MATCH before onboarding new merchants — a MATCH listing effectively prevents a merchant from obtaining card acceptance with any major acquirer."},
  {q:"What evidence is most effective for merchants disputing an 'Item Not Received' chargeback for a physical product?", options:["The original authorization approval code","Delivery confirmation with carrier tracking showing the item was delivered to the billing address","The consumer's purchase history showing prior orders","The merchant's stated return policy"], answer:1, explanation:"For 'Item Not Received' chargebacks, the most compelling evidence is carrier tracking confirmation showing the package was delivered to the cardholder's confirmed address. Signature confirmation (for high-value items) is even stronger. Without delivery proof, merchants typically lose these disputes."},

  /* ── PREPAID CARDS (79-86) ── */
  {q:"What distinguishes an 'open-loop' prepaid card from a 'closed-loop' prepaid card?", options:["Open-loop cards have no spending limits; closed-loop cards have limits","Open-loop cards carry network branding (Visa, MC) and are accepted anywhere the network operates; closed-loop cards are only accepted at the issuing merchant","Open-loop cards are government-issued; closed-loop are bank-issued","Open-loop cards can be reloaded; closed-loop cannot"], answer:1, explanation:"Open-loop prepaid cards (Visa, Mastercard, Amex branded) can be used anywhere that network is accepted — worldwide. Closed-loop cards (Starbucks gift card, Amazon gift card, Target gift card) are only redeemable at the specific merchant or its affiliates. The network relationship (or lack thereof) is the defining distinction."},
  {q:"The CFPB Prepaid Rule (effective April 2019) extended which protections to prepaid account holders?", options:["FDIC insurance of up to $250,000","Reg E-style error resolution, mandatory fee disclosures, and online account access requirements","The right to dispute charges with the card network directly","Interest payment on prepaid balances"], answer:1, explanation:"The CFPB Prepaid Rule extended meaningful consumer protections to prepaid accounts: Reg E-style unauthorized transaction protections and error resolution, standardized short-form and long-form fee disclosures, 30-day waiting period before linking credit products, and requirements to provide account history access online."},
  {q:"GPR stands for what in the prepaid card industry?", options:["Government Payment Restriction","General Purpose Reloadable — a prepaid card that can be reloaded and used for general purchases","Global Payment Rail","Guaranteed Payment Receipt"], answer:1, explanation:"GPR (General Purpose Reloadable) refers to open-loop prepaid cards marketed to consumers as bank account substitutes — primarily the unbanked and underbanked population. Examples: Walmart MoneyCard, Green Dot, NetSpend. They support direct deposit, ATM access, and online bill pay."},
  {q:"Why do small bank-issued GPR prepaid cards earn full market-rate interchange rather than the Durbin-capped rate?", options:["GPR cards use a different network than debit cards","Issuers of GPR cards under $10B in assets are exempt from the Durbin interchange cap","The CFPB granted all prepaid cards an interchange exemption","Prepaid cards always have higher interchange than debit cards"], answer:1, explanation:"GPR prepaid programs typically partner with small banks under the $10 billion Durbin threshold. These small bank issuers are exempt from the Durbin cap and can earn full market-rate debit interchange (~$0.50-$0.80 per transaction). This economics makes GPR cards fundable for neobanks and fintech programs."},
  {q:"What is a 'program manager' in the GPR prepaid industry?", options:["A bank employee who manages the prepaid card portfolio","A non-bank company that handles distribution, marketing, customer service, and program administration for prepaid cards, partnering with an issuing bank for the license and BIN","A regulatory officer who oversees prepaid card programs","The CEO of a prepaid card company"], answer:1, explanation:"Program managers are non-bank companies that operate prepaid card programs using a bank's license and BIN. Examples: NetSpend, InComm, Blackhawk Network. The bank (e.g., Bancorp Bank, Pathward/MetaBank) provides the banking charter; the program manager handles everything else. Revenue is split between them."},
  {q:"Which type of prepaid card is exempt from the Durbin Amendment interchange cap under federal regulations?", options:["All prepaid cards are exempt","General purpose reloadable cards issued by small banks","Government benefit cards (e.g., EBT, unemployment benefits) and health FSA/HRA cards","Only Visa-branded prepaid cards"], answer:2, explanation:"The Durbin Amendment specifically exempts government-administered benefit program cards (EBT, SSI, unemployment) and cards used for health-related spending accounts (FSA, HRA) from the interchange cap. These programs operate under different regulatory frameworks and policy goals than commercial prepaid."},
  {q:"What is a 'Single-Use Virtual Card (SUVC)' and what is its primary benefit?", options:["A card number that resets monthly for security","A unique 16-digit card number generated for exactly one transaction, then invalidated — preventing stolen card data from being reused elsewhere","A card that can only be used at one merchant indefinitely","A virtual card with a single user (no authorized users)"], answer:1, explanation:"A SUVC is generated for exactly one transaction. After that transaction, the card number is invalidated — even if a fraudster captures the data, it's worthless. This makes SUVCs extremely secure for CNP transactions. They're widely used in corporate AP automation and by security-conscious individuals for online purchases."},
  {q:"The primary target market for GPR (General Purpose Reloadable) prepaid cards is:", options:["Wealthy investors seeking portfolio diversification","Unbanked and underbanked consumers (approximately 77 million US adults) who lack or distrust traditional bank accounts","Corporate employees for T&E expense management","International travelers needing multi-currency access"], answer:1, explanation:"GPR prepaid primarily serves the unbanked (~22 million US adults without any bank account) and underbanked (~55 million who have accounts but rely on alternative financial services). These consumers use GPR cards as checking account substitutes — loading wages via direct deposit, paying bills, and accessing cash at ATMs."},

  /* ── COMMERCIAL CARDS (87-100) ── */
  {q:"What is a 'Purchasing Card' (P-Card)?", options:["A personal purchasing card for individual consumers","A corporate card specifically designed for high-volume procurement — replacing purchase orders and checks for routine business buying","A card that only works at a single purchasing company","A government procurement card for federal agencies only"], answer:1, explanation:"P-Cards are company-issued cards for employees to purchase goods and services on the company's behalf — eliminating slow paper processes (POs, invoices, check cutting) for routine purchases. They carry company liability, MCC controls, spend limits, and can capture Level 2/3 data for lower interchange and better reporting."},
  {q:"What is 'Level 3 data' on a commercial card transaction and why does it matter?", options:["A security classification requiring three-factor authentication","Full line-item purchase detail (item description, quantity, unit price, product codes, tax, freight) transmitted with the payment — earning lower interchange rates and enabling better spend analysis","A data transmission standard used only for government purchases","Three separate authorization attempts before declining a commercial card"], answer:1, explanation:"Level 3 data is the richest data tier for commercial card transactions — including individual line items, quantities, unit prices, commodity codes, tax amounts, and freight. Submitting Level 3 data earns significantly lower interchange rates (the network's risk premium is reduced by better data visibility) and provides granular spend analytics."},
  {q:"In a corporate card program with 'individual liability,' who is legally responsible for paying the card balance?", options:["The employing company","The individual employee is personally liable; the company reimburses through the expense management process","Both the employee and company share equal liability","The card network guarantees payment regardless of who defaults"], answer:1, explanation:"Individual liability means the employee is personally responsible for paying the card bill. The company reimburses the employee after expense reports are submitted and approved. This requires personal credit checks on employees, but protects the company's credit profile if employees misuse cards."},
  {q:"What is a 'Fleet Card' used for?", options:["Managing company employee air travel and hotel bookings","Controlling fuel and vehicle maintenance spending for company vehicle fleets — with MCC restrictions, odometer capture, and driver ID","A card used exclusively by shipping/logistics fleet managers for purchasing","A co-branded card between a car manufacturer and a bank"], answer:1, explanation:"Fleet cards are specialized commercial cards for managing vehicle fleet expenses — primarily fuel and maintenance. They feature MCC controls (restricted to gas stations and auto repair merchants), driver/vehicle ID capture, odometer reading at the pump, and integration with fleet management and IFTA tax reporting systems."},
  {q:"WEX Inc. is best known for operating which type of commercial card network?", options:["A closed-loop fleet card network accepted at partner fuel stations and service centers","A co-branded airline travel card network","A GPR prepaid card program for payroll","An international wire transfer network for commercial payments"], answer:0, explanation:"WEX (formerly Wright Express) operates one of the largest closed-loop fleet card networks in North America — accepted at thousands of fuel stations and maintenance locations. WEX also processes fleet data (odometer, driver ID, fuel grade) and provides fleet analytics. It has expanded into healthcare and corporate payments."},
  {q:"What is a 'Ghost Card' (or Lodge Card) in commercial card programs?", options:["A virtual card number used once and deleted","A card account with no physical card — the account number is shared with specific vendors for recurring charges (common in travel management for hotel master billing)","A card that is hidden from company expense reports","A card with no credit limit"], answer:1, explanation:"A Ghost/Lodge Card is a card account without a physical card. The account number is pre-shared with specific vendors — commonly hotels, airlines, or rental car companies in managed travel programs. The vendor charges the account number directly for all bookings, enabling centralized billing without individual employee cards."},
  {q:"The 'rebate' in a corporate P-Card program refers to:", options:["A refund consumers get from the IRS at year-end","Revenue sharing by the bank issuer with the corporate buyer — typically 0.5-1.5% of annual card spend — to incentivize card usage over checks","A discount the merchant gives to corporate buyers","A government subsidy for businesses using electronic payments"], answer:1, explanation:"Banks share interchange revenue with their corporate card customers as rebates — the buyer receives 0.5-1.5% of annual spend back, usually paid at year-end. For a $10M annual P-Card program at 1% rebate, the company earns $100,000. This rebate income is a major driver of corporate card program adoption."},
  {q:"Why does commercial card interchange tend to be HIGHER than consumer credit card interchange?", options:["Commercial cards are harder to produce","Higher spending limits create more risk for the issuer","Commercial transactions require Level 3 data submission","Higher interchange on commercial cards compensates for lower transaction volume per card"], answer:1, explanation:"Commercial card interchange is higher (2.5-3.5%) partly because commercial transactions tend to be larger in dollar value and carry different risk profiles. The higher interchange also funds the rebate programs that incentivize corporate adoption. However, when Level 3 data is submitted, interchange can drop significantly — sometimes below standard consumer rates."},
  {q:"AP automation via virtual cards is primarily replacing which traditional payment method in B2B transactions?", options:["ACH credit transfers","International wire transfers","Paper checks — which still account for ~40-50% of US B2B payments","Cash payments between businesses"], answer:2, explanation:"Virtual card AP automation targets paper check replacement. Despite decades of digital payment options, approximately 40-50% of US B2B payments still use paper checks (expensive to process at $3-20 each). Virtual cards offer faster payment, rebate income, and processing costs under $0.50 — a compelling ROI for AP departments."},
  {q:"What is the primary reason many suppliers resist accepting virtual card payments in AP automation programs?", options:["Virtual cards are technically too complex for suppliers to process","Suppliers must pay the full MDR (2.5-3.5%) to accept virtual cards — which can be significant on thin-margin invoices","Virtual cards don't work with most supplier ERP systems","Suppliers prefer to receive wire transfers"], answer:1, explanation:"Merchant Discount Rate is the primary obstacle. A supplier with a 5% profit margin paying 2.5-3.5% MDR to accept a virtual card sees significant margin erosion. Solutions include dynamic discounting (early pay discount that offsets the MDR), negotiated lower MDR tiers for high-volume suppliers, or program managers that can convert some payments to ACH when MDR isn't workable."},
  {q:"Which company is considered the dominant issuer in the corporate T&E (Travel & Entertainment) card segment?", options:["JPMorgan Chase","Citibank","American Express","Bank of America"], answer:2, explanation:"American Express dominates corporate T&E card programs globally. Amex GCP (Global Corporate Payments) is the standard in enterprise T&E, offering premium travel benefits, superior expense data analytics, travel insurance, and airport lounge access. This dominance stems from Amex's closed-loop model giving it superior transaction data."},
  {q:"IFTA reporting, captured by fleet card programs, relates to:", options:["IRS tax withholding from employee expense reimbursements","International Fuel Tax Agreement — fuel tax compliance for interstate commercial truckers based on miles driven in each state/province","International Financial Transactions Act — cross-border payment reporting","Import Freight Tariff Accounting — a customs fee framework"], answer:1, explanation:"IFTA (International Fuel Tax Agreement) is a fuel tax program for interstate commercial motor carriers. Trucking companies must report fuel purchased and miles driven in each IFTA jurisdiction, then pay or receive credits based on their proportional fuel consumption. Fleet cards that capture state-by-state fuel purchase data automate much of this compliance reporting."},
  {q:"A company wants its employees to use a single card for both T&E travel expenses and office supply purchases, rather than separate programs. What type of card program is this?", options:["Ghost Card program","Fleet Card with MCC overrides","One Card (Single Card) program combining T&E and purchasing","A co-branded card with multiple merchant partners"], answer:2, explanation:"A 'One Card' or 'Corporate Card' program consolidates T&E and purchasing capabilities into a single card per employee. It simplifies program administration, reduces the number of card products to manage, and gives employees more flexibility — while still maintaining MCC controls and spending limits where needed."}
];
